package com.app.logging

import android.content.Context

data class LogConfig(
    val minLogLevel: LogLevel = LogLevel.INFO,
    val enableFileLogging: Boolean = false,
    val enableConsoleLogging: Boolean = true,
    val maxLogFileSizeBytes: Long = 5 * 1024 * 1024, // 5MB
    val maxLogFiles: Int = 3,
    val enableAuthLogging: Boolean = true,
    val enableDatabaseLogging: Boolean = true,
    val enableApiLogging: Boolean = true,
    val enableExceptionLogging: Boolean = true,
    val logRetentionDays: Int = 7
) {
    companion object {
        fun forDebug() = LogConfig(
            minLogLevel = LogLevel.DEBUG,
            enableFileLogging = true,
            enableConsoleLogging = true
        )

        fun forProduction() = LogConfig(
            minLogLevel = LogLevel.INFO,
            enableFileLogging = true,
            enableConsoleLogging = false,
            enableAuthLogging = true,
            enableDatabaseLogging = true,
            enableApiLogging = true,
            enableExceptionLogging = true
        )
    }
}

