package com.app.logging

import android.content.Context
import java.io.File
import java.io.FileOutputStream
import java.io.OutputStreamWriter
import java.text.SimpleDateFormat
import java.util.*
import java.util.concurrent.ConcurrentLinkedQueue
import java.util.concurrent.Executors
import java.util.concurrent.atomic.AtomicBoolean

class SecureFileLogger(
    private val context: Context,
    private val config: LogConfig
) {
    private val logDirectory: File by lazy {
        File(context.filesDir, "secure_logs").also { dir ->
            if (!dir.exists()) dir.mkdirs()
            // Ensure directory permissions are restrictive
            dir.setReadable(true, true)
            dir.setWritable(true, true)
            dir.setExecutable(true, true)
        }
    }

    private val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    private val timestampFormat = SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", Locale.US).apply {
        timeZone = TimeZone.getTimeZone("UTC")
    }

    private val writeExecutor = Executors.newSingleThreadExecutor { r ->
        Thread(r, "SecureFileLogger").apply { isDaemon = true }
    }

    private val buffer = ConcurrentLinkedQueue<String>()
    private val isFlushing = AtomicBoolean(false)

    fun write(level: LogLevel, tag: String, message: String) {
        val timestamp = timestampFormat.format(Date())
        val logLine = "$timestamp [${level.name}] [$tag] $message\n"
        buffer.add(logLine)

        if (buffer.size >= 10 || level.priority >= LogLevel.ERROR.priority) {
            flush()
        }
    }

    fun flush() {
        if (!isFlushing.compareAndSet(false, true)) return

        writeExecutor.execute {
            try {
                val entries = mutableListOf<String>()
                while (buffer.isNotEmpty()) {
                    buffer.poll()?.let { entries.add(it) }
                }

                if (entries.isNotEmpty()) {
                    val logFile = getCurrentLogFile()
                    rotateIfNeeded(logFile)

                    FileOutputStream(logFile, true).use { fos ->
                        OutputStreamWriter(fos, Charsets.UTF_8).use { writer ->
                            entries.forEach { writer.write(it) }
                            writer.flush()
                        }
                    }
                }
            } catch (e: Exception) {
                // Avoid recursive logging; use Android's built-in as fallback
                android.util.Log.e("SecureFileLogger", "Failed to write logs", e)
            } finally {
                isFlushing.set(false)
            }
        }
    }

    private fun getCurrentLogFile(): File {
        val fileName = "app_log_${dateFormat.format(Date())}.log"
        return File(logDirectory, fileName).also { file ->
            file.setReadable(true, true)
            file.setWritable(true, true)
        }
    }

    private fun rotateIfNeeded(currentFile: File) {
        if (currentFile.exists() && currentFile.length() > config.maxLogFileSizeBytes) {
            val rotatedName = "${currentFile.nameWithoutExtension}_${System.currentTimeMillis()}.log"
            currentFile.renameTo(File(logDirectory, rotatedName))
        }

        // Clean up old files
        cleanOldLogs()
    }

    fun cleanOldLogs() {
        val cutoffTime = System.currentTimeMillis() - (config.logRetentionDays * 24 * 60 * 60 * 1000L)
        logDirectory.listFiles()?.let { files ->
            val logFiles = files.filter { it.extension == "log" }.sortedByDescending { it.lastModified() }

            logFiles.forEachIndexed { index, file ->
                if (index >= config.maxLogFiles || file.lastModified() < cutoffTime) {
                    file.delete()
                }
            }
        }
    }

    fun getLogFiles(): List<File> {
        return logDirectory.listFiles()
            ?.filter { it.extension == "log" }
            ?.sortedByDescending { it.lastModified() }
            ?: emptyList()
    }

    fun shutdown() {
        flush()
        writeExecutor.shutdown()
    }
}

