package com.app.logging

import android.content.Context
import timber.log.Timber
import java.text.SimpleDateFormat
import java.util.*
import java.util.concurrent.atomic.AtomicReference

object AppLogger {

    private val configRef = AtomicReference(LogConfig.forProduction())
    private var fileLogger: SecureFileLogger? = null
    private val sessionId = UUID.randomUUID().toString().take(8)

    private val timestampFormat = SimpleDateFormat("HH:mm:ss.SSS", Locale.US)

    fun initialize(context: Context, config: LogConfig) {
        configRef.set(config)

        Timber.uprootAll()

        if (config.enableConsoleLogging) {
            Timber.plant(Timber.DebugTree())
        }

        if (config.enableFileLogging) {
            fileLogger = SecureFileLogger(context.applicationContext, config)
            Timber.plant(FileLoggingTree(fileLogger!!, config))
        }

        Timber.plant(ProductionSafeTree(config))

        info("Logger", "Logging initialized | session=$sessionId | level=${config.minLogLevel}")
    }

    fun updateConfig(config: LogConfig) {
        configRef.set(config)
    }

    private fun shouldLog(level: LogLevel): Boolean {
        return level.priority >= configRef.get().minLogLevel.priority
    }

    // ---- Generic logging methods ----

    fun verbose(tag: String, message: String) {
        if (shouldLog(LogLevel.VERBOSE)) {
            Timber.tag(tag).v(message)
        }
    }

    fun debug(tag: String, message: String) {
        if (shouldLog(LogLevel.DEBUG)) {
            Timber.tag(tag).d(message)
        }
    }

    fun info(tag: String, message: String) {
        if (shouldLog(LogLevel.INFO)) {
            Timber.tag(tag).i(message)
        }
    }

    fun warn(tag: String, message: String, throwable: Throwable? = null) {
        if (shouldLog(LogLevel.WARN)) {
            if (throwable != null) {
                Timber.tag(tag).w(throwable, message)
            } else {
                Timber.tag(tag).w(message)
            }
        }
    }

    fun error(tag: String, message: String, throwable: Throwable? = null) {
        if (shouldLog(LogLevel.ERROR)) {
            if (throwable != null) {
                Timber.tag(tag).e(throwable, message)
            } else {
                Timber.tag(tag).e(message)
            }
        }
    }

    // ---- Authentication Logging ----

    fun logAuthAttempt(
        username: String,
        method: String,
        success: Boolean,
        failureReason: String? = null,
        ipAddress: String? = null,
        additionalContext: Map<String, String> = emptyMap()
    ) {
        if (!configRef.get().enableAuthLogging) return

        val redactedUser = SensitiveDataRedactor.redactUsername(username)
        val status = if (success) "SUCCESS" else "FAILED"

        val sb = StringBuilder()
        sb.append("AUTH_$status | ")
        sb.append("user=$redactedUser | ")
        sb.append("method=$method")

        if (!success && !failureReason.isNullOrBlank()) {
            // Only log safe failure reasons, not detailed error messages that might leak info
            val safeReason = sanitizeFailureReason(failureReason)
            sb.append(" | reason=$safeReason")
        }

        // Redact IP to partial for privacy
        ipAddress?.let {
            sb.append(" | ip=${redactIpAddress(it)}")
        }

        additionalContext.forEach { (key, value) ->
            // Don't log values that might be sensitive
            if (!isSensitiveKey(key)) {
                sb.append(" | $key=$value")
            }
        }

        sb.append(" | session=$sessionId")
        sb.append(" | ts=${timestampFormat.format(Date())}")

        if (success) {
            info("AUTH", sb.toString())
        } else {
            warn("AUTH", sb.toString())
        }
    }

    // ---- Database Query Logging ----

    fun logDatabaseQuery(
        queryType: String, // SELECT, INSERT, UPDATE, DELETE
        table: String,
        params: Map<String, Any?> = emptyMap(),
        executionTimeMs: Long = -1,
        rowsAffected: Int = -1,
        success: Boolean = true,
        error: Throwable? = null
    ) {
        if (!configRef.get().enableDatabaseLogging) return

        val redactedParams = SensitiveDataRedactor.redactQueryParams(params)

        val sb = StringBuilder()
        sb.append("DB_${queryType.uppercase()} | ")
        sb.append("table=$table")

        if (redactedParams.isNotEmpty()) {
            sb.append(" | params=$redactedParams")
        }

        if (executionTimeMs >= 0) {
            sb.append(" | duration=${executionTimeMs}ms")
        }

        if (rowsAffected >= 0) {
            sb.append(" | rows=$rowsAffected")
        }

        sb.append(" | success=$success")

        if (!success && error != null) {
            // Log error type but not full message which might contain query data
            sb.append(" | error=${error.javaClass.simpleName}")
        }

        if (executionTimeMs > 1000) {
            warn("DB", "SLOW_QUERY: $sb")
        } else if (!success) {
            error("DB", sb.toString(), error)
        } else {
            debug("DB", sb.toString())
        }
    }

    fun logDatabaseTransaction(
        operation: String,
        tables: List<String>,
        success: Boolean,
        durationMs: Long,
        error: Throwable? = null
    ) {
        if (!configRef.get().enableDatabaseLogging) return

        val sb = StringBuilder()
        sb.append("DB_TXN | ")
        sb.append("op=$operation | ")
        sb.append("tables=${tables.joinToString(",")} | ")
        sb.append("duration=${durationMs}ms | ")
        sb.append("success=$success")

        if (!success) {
            error("DB", sb.toString(), error)
        } else {
            info("DB", sb.toString())
        }
    }

    // ---- API Request/Response Logging ----

    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        contentType: String? = null,
        requestId: String = UUID.randomUUID().toString().take(8)
    ): String {
        if (!configRef.get().enableApiLogging) return requestId

        val redactedUrl = SensitiveDataRedactor.redactUrl(url)
        val redactedHeaders = SensitiveDataRedactor.redactHeaders(headers)
        val redactedBody = body?.let {
            SensitiveDataRedactor.redactBody(it, contentType)
        }

        val sb = StringBuilder()
        sb.append("API_REQ | ")
        sb.append("id=$requestId | ")
        sb.append("$method $redactedUrl")

        if (redactedHeaders.isNotEmpty()) {
            sb.append(" | headers=$redactedHeaders")
        }

        if (!redactedBody.isNullOrBlank()) {
            // Truncate very large bodies
            val truncatedBody = if (redactedBody.length > 2000) {
                "${redactedBody.take(2000)}...[TRUNCATED ${redactedBody.length} chars]"
            } else {
                redactedBody
            }
            sb.append(" | body=$truncatedBody")
        }

        info("API", sb.toString())
        return requestId
    }

    fun logApiResponse(
        requestId: String,
        method: String,
        url: String,
        statusCode: Int,
        responseBody: String? = null,
        contentType: String? = null,
        durationMs: Long = -1,
        headers: Map<String, String> = emptyMap()
    ) {
        if (!configRef.get().enableApiLogging) return

        val redactedUrl = SensitiveDataRedactor.redactUrl(url)
        val redactedHeaders = SensitiveDataRedactor.redactHeaders(headers)
        val redactedBody = responseBody?.let {
            SensitiveDataRedactor.redactBody(it, contentType)
        }

        val sb = StringBuilder()
        sb.append("API_RES | ")
        sb.append("id=$requestId | ")
        sb.append("$method $redactedUrl | ")
        sb.append("status=$statusCode")

        if (durationMs >= 0) {
            sb.append(" | duration=${durationMs}ms")
        }

        if (redactedHeaders.isNotEmpty()) {
            sb.append(" | headers=$redactedHeaders")
        }

        if (!redactedBody.isNullOrBlank()) {
            val truncatedBody = if (redactedBody.length > 2000) {
                "${redactedBody.take(2000)}...[TRUNCATED ${redactedBody.length} chars]"
            } else {
                redactedBody
            }
            sb.append(" | body=$truncatedBody")
        }

        when {
            statusCode in 200..299 -> info("API", sb.toString())
            statusCode in 400..499 -> warn("API", sb.toString())
            statusCode >= 500 -> error("API", sb.toString())
            else -> info("API", sb.toString())
        }

        if (durationMs > 5000) {
            warn("API", "SLOW_REQUEST: id=$requestId | ${durationMs}ms | $method $redactedUrl")
        }
    }

    fun logApiError(
        requestId: String,
        method: String,
        url: String,
        throwable: Throwable,
        durationMs: Long = -1
    ) {
        if (!configRef.get().enableApiLogging) return

        val redactedUrl = SensitiveDataRedactor.redactUrl(url)

        val sb = StringBuilder()
        sb.append("API_ERR | ")
        sb.append("id=$requestId | ")
        sb.append("$method $redactedUrl | ")
        sb.append("error=${throwable.javaClass.simpleName}: ${throwable.message ?: "unknown"}")

        if (durationMs >= 0) {
            sb.append(" | duration=${durationMs}ms")
        }

        error("API", sb.toString(), throwable)
    }

    // ---- Exception Logging ----

    fun logException(
        tag: String,
        throwable: Throwable,
        context: String? = null,
        additionalData: Map<String, String> = emptyMap()
    ) {
        if (!configRef.get().enableExceptionLogging) return

        val sb = StringBuilder()
        sb.append("EXCEPTION | ")
        sb.append("type=${throwable.javaClass.name}")

        context?.let {
            sb.append(" | context=$it")
        }

        additionalData.forEach { (key, value) ->
            if (!isSensitiveKey(key)) {
                sb.append(" | $key=$value")
            }
        }

        sb.append(" | session=$sessionId")
        sb.appendLine()
        sb.append(SensitiveDataRedactor.redactStackTrace(throwable))

        error(tag, sb.toString())
    }

    fun logUncaughtException(thread: Thread, throwable: Throwable) {
        val sb = StringBuilder()
        sb.append("UNCAUGHT_EXCEPTION | ")
        sb.append("thread=${thread.name} | ")
        sb.append("type=${throwable.javaClass.name} | ")
        sb.append("session=$sessionId")
        sb.appendLine()
        sb.append(SensitiveDataRedactor.redactStackTrace(throwable, maxDepth = 50))

        error("CRASH", sb.toString())
        fileLogger?.flush()
    }

    // ---- Lifecycle / Performance Logging ----

    fun logPerformance(tag: String, operation: String, durationMs: Long, metadata: Map<String, String> = emptyMap()) {
        val sb = StringBuilder()
        sb.append("PERF | op=$operation | duration=${durationMs}ms")
        metadata.forEach { (key, value) ->
            if (!isSensitiveKey(key)) {
                sb.append(" | $key=$value")
            }
        }

        if (durationMs > 3000) {
            warn(tag, sb.toString())
        } else {
            debug(tag, sb.toString())
        }
    }

    // ---- Utility ----

    fun getLogFiles(): List<java.io.File> {
        return fileLogger?.getLogFiles() ?: emptyList()
    }

    fun cleanOldLogs() {
        fileLogger?.cleanOldLogs()
    }

    fun shutdown() {
        info("Logger", "Shutting down logger | session=$sessionId")
        fileLogger?.shutdown()
    }

    private fun sanitizeFailureReason(reason: String): String {
        val safeReasons = setOf(
            "invalid_credentials", "account_locked", "account_disabled",
            "mfa_required", "mfa_failed", "session_expired",
            "rate_limited", "network_error", "server_error",
            "invalid_token", "token_expired", "unknown"
        )

        val normalized = reason.lowercase().replace(" ", "_")
        return if (safeReasons.contains(normalized)) {
            normalized
        } else {
            "auth_failure"
        }
    }

    private fun redactIpAddress(ip: String): String {
        return if (ip.contains(".")) {
            // IPv4: show first two octets
            val parts = ip.split(".")
            if (parts.size == 4) "${parts[0]}.${parts[1]}.*.*" else "[redacted_ip]"
        } else if (ip.contains(":")) {
            // IPv6: show first segment
            val parts = ip.split(":")
            "${parts.firstOrNull() ?: ""}:****"
        } else {
            "[redacted_ip]"
        }
    }

    private fun isSensitiveKey(key: String): Boolean {
        val sensitiveKeys = setOf(
            "password", "token", "secret", "key", "credential",
            "auth", "ssn", "credit_card", "cvv", "pin"
        )
        return sensitiveKeys.any { key.lowercase().contains(it) }
    }
}

