package com.app.logging

import android.util.Log
import timber.log.Timber

class ProductionSafeTree(private val config: LogConfig) : Timber.Tree() {

    override fun isLoggable(tag: String?, priority: Int): Boolean {
        return priority >= config.minLogLevel.priority
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        // In production, we don't log to console (logcat) to prevent
        // sensitive data from appearing in system logs accessible by other apps
        if (!config.enableConsoleLogging) return

        // Even with console logging enabled, ensure we don't log VERBOSE in production
        if (priority < Log.INFO && config.minLogLevel.priority >= LogLevel.INFO.priority) return

        // Use Android's Log as fallback
        when (priority) {
            Log.VERBOSE -> Log.v(tag, message)
            Log.DEBUG -> Log.d(tag, message)
            Log.INFO -> Log.i(tag, message)
            Log.WARN -> Log.w(tag, message)
            Log.ERROR -> Log.e(tag, message)
            else -> Log.i(tag, message)
        }
    }
}

