package com.app.logging

import android.util.Log
import timber.log.Timber

class FileLoggingTree(
    private val fileLogger: SecureFileLogger,
    private val config: LogConfig
) : Timber.Tree() {

    override fun isLoggable(tag: String?, priority: Int): Boolean {
        return priority >= config.minLogLevel.priority
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val level = when (priority) {
            Log.VERBOSE -> LogLevel.VERBOSE
            Log.DEBUG -> LogLevel.DEBUG
            Log.INFO -> LogLevel.INFO
            Log.WARN -> LogLevel.WARN
            Log.ERROR -> LogLevel.ERROR
            else -> LogLevel.INFO
        }

        val fullMessage = if (t != null) {
            "$message\n${SensitiveDataRedactor.redactStackTrace(t)}"
        } else {
            message
        }

        fileLogger.write(level, tag ?: "APP", fullMessage)
    }
}

