// File: logging/DatabaseLogger.kt (Room/SQLite helper)
// ============================================================
package com.app.logging

class DatabaseLogger {

    inline fun <T> logQuery(
        queryType: String,
        table: String,
        params: Map<String, Any?> = emptyMap(),
        block: () -> T
    ): T {
        val startTime = System.currentTimeMillis()
        var success = true
        var error: Throwable? = null
        var result: T

        try {
            result = block()
        } catch (e: Throwable) {
            success = false
            error = e
            throw e
        } finally {
            val duration = System.currentTimeMillis() - startTime
            AppLogger.logDatabaseQuery(
                queryType = queryType,
                table = table,
                params = params,
                executionTimeMs = duration,
                success = success,
                error = error
            )
        }

        return result
    }

    inline fun <T> logTransaction(
        operation: String,
        tables: List<String>,
        block: () -> T
    ): T {
        val startTime = System.currentTimeMillis()
        var success = true
        var error: Throwable? = null

        try {
            return block()
        } catch (e: Throwable) {
            success = false
            error = e
            throw e
        } finally {
            val duration = System.currentTimeMillis() - startTime
            AppLogger.logDatabaseTransaction(
                operation = operation,
                tables = tables,
                success = success,
                durationMs = duration,
                error = error
            )
        }
    }
}

