// File: logging/PerformanceTracker.kt
// ============================================================
package com.app.logging

class PerformanceTracker(private val tag: String, private val operation: String) {
    private val startTime = System.currentTimeMillis()
    private val metadata = mutableMapOf<String, String>()

    fun addMetadata(key: String, value: String): PerformanceTracker {
        metadata[key] = value
        return this
    }

    fun stop() {
        val duration = System.currentTimeMillis() - startTime
        AppLogger.logPerformance(tag, operation, duration, metadata)
    }

    companion object {
        fun start(tag: String, operation: String): PerformanceTracker {
            return PerformanceTracker(tag, operation)
        }
    }
}

// ============================================================
// File: App.kt (Application class showing initialization)
// ============================================================
package com.app

import android.app.Application
import com.app.logging.AppLogger
import com.app.logging.LogConfig

class App : Application() {

    override fun onCreate() {
        super.onCreate()

        // Initialize logging
        val config = if (BuildConfig.DEBUG) {
            LogConfig.forDebug()
        } else {
            LogConfig.forProduction()
        }

        AppLogger.initialize(this, config)

        // Set up uncaught exception handler
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            AppLogger.logUncaughtException(thread, throwable)
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }

    override fun onTerminate() {
        AppLogger.shutdown()
        super.onTerminate()
    }
}

