package com.app.example

import com.app.logging.AppLogger
import com.app.logging.DatabaseLogger
import com.app.logging.LoggingInterceptor
import com.app.logging.PerformanceTracker
import okhttp3.OkHttpClient

class ExampleUsage {

    private val dbLogger = DatabaseLogger()

    // Example: Authentication logging
    fun loginUser(username: String, password: String) {
        try {
            // Perform authentication (password is NEVER logged)
            val success = performAuth(username, password)

            AppLogger.logAuthAttempt(
                username = username,
                method = "password",
                success = success,
                failureReason = if (!success) "invalid_credentials" else null,
                additionalContext = mapOf("platform" to "android", "app_version" to "1.0.0")
            )
        } catch (e: Exception) {
            AppLogger.logAuthAttempt(
                username = username,
                method = "password",
                success = false,
                failureReason = "server_error"
            )
            AppLogger.logException("AUTH", e, context = "login_attempt")
        }
    }

    // Example: Database query logging
    fun getUserById(userId: Long): Any? {
        return dbLogger.logQuery(
            queryType = "SELECT",
            table = "users",
            params = mapOf("id" to userId)
        ) {
            // Actual database query here
            // e.g., userDao.findById(userId)
            null
        }
    }

    // Example: Database transaction logging
    fun transferFunds(fromId: Long, toId: Long, amount: Double) {
        dbLogger.logTransaction(
            operation = "transfer_funds",
            tables = listOf("accounts", "transactions")
        ) {
            // Actual transaction logic
        }
    }

    // Example: OkHttp client with logging interceptor
    fun createHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(LoggingInterceptor())
            .build()
    }

    // Example: Performance tracking
    fun loadDashboard() {
        val tracker = PerformanceTracker.start("Dashboard", "full_load")
        tracker.addMetadata("screen" , "main_dashboard")

        try {
            // Load data...
            Thread.sleep(100) // Simulated work
        } finally {
            tracker.stop()
        }
    }

    // Example: Exception logging with context
    fun processPayment(orderId: String) {
        try {
            // Payment processing...
            throw RuntimeException("Payment gateway timeout")
        } catch (e: Exception) {
            AppLogger.logException(
                tag = "PAYMENT",
                throwable = e,
                context = "process_payment",
                additionalData = mapOf(
                    "order_id" to orderId,
                    "step" to "gateway_call"
                    // Note: amount, card details etc. are NOT included
                )
            )
        }
    }

    private fun performAuth(username: String, password: String): Boolean {
        // Simulated auth
        return username.isNotBlank() && password.isNotBlank()
    }
}